+    for (slot, byte) in rr.name.iter_mut().zip(b"foo.com\0") {
+        *slot = *byte as c_char;
+    }
+    rr._type = 1;
+    rr.rr_class = 1;
+    let rdata = [127u8, 0, 0, 1];
+    rr.rdata = rdata.as_ptr();
+    rr.rdlength = 4;
+
+    let mut buf = [0u8; 64];
+    let n = unsafe {
+        ns_sprintrr(
+            &handle,
+            &rr,
+            std::ptr::null(),
+            std::ptr::null(),
+            buf.as_mut_ptr() as *mut c_char,
